param(     [string]$Owner = "heonly",     [string]$Repo = "kelivo-win7",     [string]$Branch = "main",     [string]$LastSyncedCommit = "8c432494ad3c01e40a955607f77be87d61e0879a" )  $ErrorActionPreference = "Stop" $apiBase = "/repos/$Owner/$Repo"  function Invoke-GhApi {     param([string]$Method, [string]$Url, [string]$Body)     $tmpFile = [System.IO.Path]::GetTempFileName()     try {         $utf8NoBom = New-Object System.Text.UTF8Encoding $false         [System.IO.File]::WriteAllText($tmpFile, $Body, $utf8NoBom)         $output = gh api -X $Method $Url --input $tmpFile 2>$null         if ($LASTEXITCODE -ne 0) {             $err = gh api -X $Method $Url --input $tmpFile 2>&1             throw "gh api failed (exit $LASTEXITCODE): $err"         }         return $output | ConvertFrom-Json     } finally {         if (Test-Path $tmpFile) { Remove-Item $tmpFile -Force }     } }  $commits = git rev-list --reverse "$LastSyncedCommit..HEAD" 2>$null if (-not $commits) {     Write-Host "No new commits found between $LastSyncedCommit and HEAD."     exit 0 }  $commitCount = @($commits).Count Write-Host "Found $commitCount commit(s) to push`n"  $parentSha = $LastSyncedCommit  foreach ($commit in $commits) {     Write-Host "=== Processing commit $commit ==="      $authorName = git show --format="%an" --no-patch $commit     $authorEmail = git show --format="%ae" --no-patch $commit     $authorTimestamp = git show --format="%at" --no-patch $commit     $authorDate = [DateTimeOffset]::FromUnixTimeSeconds($authorTimestamp).ToString("o")     $subject = git show --format="%s" --no-patch $commit     $bodyMsg = git show --format="%b" --no-patch $commit     $fullMessage = if ($bodyMsg) { "$subject`n$bodyMsg" } else { $subject }      Write-Host "  $authorName <$authorEmail>"     Write-Host "  $subject"      $treeLines = git ls-tree -r $commit     $treeEntries = @()      foreach ($line in $treeLines) {         if ($line -match '^(\S+)\s+(blob)\s+(\S+)\s+(.+)$') {             $mode = $matches[1]             $sha = $matches[3]             $path = $matches[4]              Write-Host "  Blob: $path"              $tmpFile = [System.IO.Path]::GetTempFileName()             try {                 cmd /c "git cat-file -p $sha > `"$tmpFile`" 2>NUL"                 if ($LASTEXITCODE -ne 0) { throw "git cat-file failed for $path" }                 $bytes = [System.IO.File]::ReadAllBytes($tmpFile)                 $content = [Convert]::ToBase64String($bytes)             } finally {                 if (Test-Path $tmpFile) { Remove-Item $tmpFile -Force }             }              $bodyJson = @{                 content = $content                 encoding = "base64"             } | ConvertTo-Json -Compress              $result = Invoke-GhApi -Method POST -Url "$apiBase/git/blobs" -Body $bodyJson             $blobSha = $result.sha              $treeEntries += @{                 path = $path                 mode = $mode                 type = "blob"                 sha = $blobSha             }         }     }      Write-Host "  Creating tree..."     $treeBodyJson = @{         tree = $treeEntries     } | ConvertTo-Json -Compress -Depth 10      $treeResult = Invoke-GhApi -Method POST -Url "$apiBase/git/trees" -Body $treeBodyJson     $treeSha = $treeResult.sha     Write-Host "  Tree SHA: $treeSha"      Write-Host "  Creating commit..."     $commitBodyJson = @{         message = $fullMessage         author = @{             name = $authorName             email = $authorEmail             date = $authorDate         }         parents = @($parentSha)         tree = $treeSha     } | ConvertTo-Json -Compress -Depth 10      $commitResult = Invoke-GhApi -Method POST -Url "$apiBase/git/commits" -Body $commitBodyJson     $newCommitSha = $commitResult.sha     Write-Host "  Commit SHA: $newCommitSha"      Write-Host "  Updating refs/heads/$Branch..."     $refBodyJson = @{         sha = $newCommitSha         force = $true     } | ConvertTo-Json -Compress      $null = Invoke-GhApi -Method PATCH -Url "$apiBase/git/refs/heads/$Branch" -Body $refBodyJson      $parentSha = $newCommitSha     Write-Host "  -> Done`n" }  Write-Host "All commit(s) pushed successfully!"